const POSTS_PER_PAGE=10;let allPosts=[],currentIndex=0,isLoading=!1;async function loadPostsData(){try{const e=await fetch("/data/siteurls.json");return allPosts=await e.json(),allPosts.sort((e,t)=>new Date(t.date_published)-new Date(e.date_published)),!0}catch(e){return console.error("Error loading posts data:",e),document.getElementById("posts-container").innerHTML="<p>حدث خطأ في تحميل المقالات.</p>",!1}}function createPostElement(e){const t=new Date(e.date_published).toLocaleDateString("ar-SA",{year:"numeric",month:"long",day:"numeric"}),n=document.createElement("article");return n.className="post-card",n.innerHTML=`\n    <span class="post-category">${e.category}</span>\n    <h3><a href="${e.url}" style="text-decoration: none; color: inherit;">${e.title}</a></h3>\n    <time>${t}</time>\n    <p class="excerpt">${e.excerpt}</p>\n    <a href="${e.url}" class="read-more">اقرأ المزيد →</a>\n  `,n}function loadMorePosts(){if(isLoading||currentIndex>=allPosts.length)return;isLoading=!0;const e=document.getElementById("posts-container"),t=Math.min(currentIndex+10,allPosts.length);for(let n=currentIndex;n<t;n++)e.appendChild(createPostElement(allPosts[n]));currentIndex=t,isLoading=!1}function setupInfiniteScroll(){const e=document.createElement("div");e.id="scroll-sentinel",e.style.height="50px",document.getElementById("posts-container").parentElement.appendChild(e);new IntersectionObserver(e=>{e[0].isIntersecting&&currentIndex<allPosts.length&&loadMorePosts()},{rootMargin:"200px"}).observe(e)}async function initBlog(){await loadPostsData()&&(loadMorePosts(),setupInfiniteScroll())}"loading"===document.readyState?document.addEventListener("DOMContentLoaded",initBlog):initBlog();